1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	function cellWillLive(isAlive: boolean, liveNeighbors: number): boolean {
10	  return liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
11	}
12	
13	export function nextGeneration(liveCells: Cell[]): Cell[] {
14	  const liveKeys = new Set(liveCells.map(toKey));
15	  const candidates = collectNeighborCounts(liveCells);
16	
17	  return [...candidates.values()].flatMap(({ cell, count }) =>
18	    cellWillLive(liveKeys.has(toKey(cell)), count) ? [cell] : [],
19	  );
20	}
21	
22	type Candidate = { cell: Cell; count: number };
23	
24	function collectNeighborCounts(liveCells: Cell[]): Map<string, Candidate> {
25	  const candidates = new Map<string, Candidate>();
26	  for (const [x, y] of liveCells) {
27	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
28	      const neighbor: Cell = [x + dx, y + dy];
29	      const key = toKey(neighbor);
30	      const prior = candidates.get(key)?.count ?? 0;
31	      candidates.set(key, { cell: neighbor, count: prior + 1 });
32	    }
33	  }
34	  return candidates;
35	}
36	
37	function toKey([x, y]: Cell): string {
38	  return `${x},${y}`;
39	}
40

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty input returns empty array — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    expect(new Set(nextGeneration(input).map(c => c.join(",")))).toEqual(
17	      new Set(input.map(c => c.join(","))),
18	    );
19	  });
20	  it("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
21	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
22	    expect(new Set(result.map(c => c.join(",")))).toEqual(
23	      new Set(["-1,1", "0,1", "1,1"]),
24	    );
25	  });
26	  it("live cell with 2 neighbors survives (rule 2) — (1,0) in '###/.../.#.' has 2 neighbors and survives", () => {
27	    const input: [number, number][] = [[0, 0], [1, 0], [2, 0], [1, 2]];
28	    const result = nextGeneration(input);
29	    expect(new Set(result.map(c => c.join(",")))).toContain("1,0");
30	  });
31	  it("live cell with more than 3 neighbors dies from overpopulation (rule 3) — center of '###/.#./###' dies", () => {
32	    const input: [number, number][] = [
33	      [0, 0], [1, 0], [2, 0],
34	      [1, 1],
35	      [0, 2], [1, 2], [2, 2],
36	    ];
37	    const result = nextGeneration(input);
38	    expect(new Set(result.map(c => c.join(",")))).not.toContain("1,1");
39	  });
40	  it("dead cell with exactly 3 live neighbors becomes alive (rule 4) — '(1,1)' in '##./#../...' is born", () => {
41	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
42	    const result = nextGeneration(input);
43	    expect(new Set(result.map(c => c.join(",")))).toContain("1,1");
44	  });
