export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(toKey));
  const candidates = collectNeighborCounts(liveCells);

  return [...candidates].flatMap(([key, { cell, count }]) =>
    cellWillLive(liveKeys.has(key), count) ? [cell] : [],
  );
}
